// n8n Code node (Run Once for All Items)
// Aseos v2 — datos desde API Stays.net
// Fechas desde PostgreSQL (America/Santiago)

const allItems = $input.all().map(i => i.json);

// La API puede devolver array auto-split (N items) o 1 item con array
let reservas;
if (allItems.length === 0) {
  reservas = [];
} else if (allItems.length === 1 && Array.isArray(allItems[0])) {
  // HTTP devolvió 1 item con el array completo como $json
  reservas = allItems[0];
} else {
  // HTTP auto-split o 1 sola reserva
  reservas = allItems;
}

const meta = $('GetFechasYAlojamientos').first().json;
const fechaDesde = meta.fecha_desde || '';
const fechaHasta = meta.fecha_hasta || '';
const alojArr = Array.isArray(meta.alojamientos) ? meta.alojamientos : [];

// Mapa: _idlisting → nombre de alojamiento
const listingMap = {};
for (const a of alojArr) {
  if (a.listing_id) listingMap[a.listing_id] = a.listing_name || a.listing_id;
}

// ── Helpers ──
const normalizeYMD = (v) => {
  if (v === null || v === undefined) return null;
  const s = String(v);
  return s.length >= 10 ? s.slice(0, 10) : s;
};

const ddmmyyyy = (ymd) => {
  if (!ymd) return '';
  const parts = ymd.split('-');
  if (parts.length !== 3) return ymd;
  return `${parts[2]}-${parts[1]}-${parts[0]}`;
};

const dateAtNoonUTC = (ymd) => new Date(`${ymd}T12:00:00.000Z`);

const toTitleCase = (s) =>
  String(s || '').replace(/\p{L}[\p{L}\p{Mn}]*/gu, (w) => w[0].toUpperCase() + w.slice(1));

const fmtDiaES = new Intl.DateTimeFormat('es-CL', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  timeZone: 'America/Santiago',
});

const diaTextoES = (ymd) => {
  if (!ymd) return '';
  const raw = fmtDiaES.format(dateAtNoonUTC(ymd));
  return toTitleCase(raw.replace(',', ''));
};

const escapeHtml = (s) =>
  String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

// ── Agrupar: checkOutDate → deptoName → _id ──
const grouped = new Map();

for (const r of reservas) {
  const dia = normalizeYMD(r.checkOutDate);
  if (!dia) continue;
  const listingId = r._idlisting || '';
  const depto = listingMap[listingId] || listingId || 'SinDepto';
  const rid = r._id || String(Math.random());

  if (!grouped.has(dia)) grouped.set(dia, new Map());
  const byDepto = grouped.get(dia);
  if (!byDepto.has(depto)) byDepto.set(depto, new Map());
  byDepto.get(depto).set(rid, r);
}

const diasOrdenados = Array.from(grouped.keys()).sort();

const actualizado = new Intl.DateTimeFormat('es-CL', {
  timeZone: 'America/Santiago',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
}).format(new Date()).replace(',', '');

// ── Body HTML ──
let body = '';

for (const dia of diasOrdenados) {
  const byDepto = grouped.get(dia);
  const deptosOrdenados = Array.from(byDepto.keys()).sort((a, b) => a.localeCompare(b, 'es'));

  body += `
  <section class="day">
    <div class="dayHeader">
      <div class="dayTitle">${escapeHtml(ddmmyyyy(dia))} · ${escapeHtml(diaTextoES(dia))}</div>
      <div class="daySub">Check-outs del día · Fuente: API Stays.net</div>
    </div>`;

  for (const depto of deptosOrdenados) {
    const byReserva = byDepto.get(depto);
    const reservasOrdenadas = Array.from(byReserva.keys()).sort();

    body += `
    <div class="deptoCard">
      <div class="deptoHeader"><div class="deptoName">Departamento ${escapeHtml(depto)}</div></div>
      <div class="deptoItems">`;

    for (const rid of reservasOrdenadas) {
      const r = byReserva.get(rid);
      const guestName = r.guestsDetails?.list?.[0]?.name || '';
      const checkIn = normalizeYMD(r.checkInDate) || '';
      const resUrl = r.reservationUrl || '';
      const resId = r._id || rid;
      const tipo = r.type || '';
      const enlace = resUrl
        ? ' · <a class="link" href="' + escapeHtml(resUrl) + '" target="_blank" rel="noopener">Ver reserva</a>'
        : ' · ID: ' + escapeHtml(resId);

      body += `
        <div class="item">
          <div class="row">
            <div class="tag tagBlue">RESERVA</div>
            <div class="text">
              <div class="main"><span class="strong">Check-out</span> <span class="muted">· ${escapeHtml(ddmmyyyy(dia))}${tipo ? ' · ' + escapeHtml(tipo) : ''}</span></div>
              <div class="sub">${guestName ? escapeHtml(toTitleCase(guestName)) + ' · ' : ''}Check-in: ${escapeHtml(ddmmyyyy(checkIn))}${enlace}</div>
            </div>
          </div>
          <div class="row">
            <div class="tag tagRed">ASEO</div>
            <div class="text">
              <div class="main"><span class="strong red">FALTA ASEO</span></div>
              <div class="sub">Sin confirmación en base de datos · verificar manualmente</div>
            </div>
          </div>
        </div>`;
    }

    body += `
      </div>
    </div>`;
  }

  body += `
  </section>`;
}

const html = `<!doctype html>
<html lang="es">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>Aseos v2 · Stays API · SandiegoApart</title>
  <style>
    :root{
      --bg:#0b0f19;--card:#121a2a;--card2:#0f1626;
      --text:#e8eefc;--muted:#a9b6d6;--line:#223055;
      --blue:#3b82f6;--green:#22c55e;--red:#ef4444;
      --shadow:0 8px 22px rgba(0,0,0,.25);--radius:16px;
    }
    *{box-sizing:border-box}
    body{margin:0;font-family:system-ui,-apple-system,Segoe UI,Roboto,Arial;background:linear-gradient(180deg,#070a12 0%,var(--bg) 100%);color:var(--text)}
    .wrap{max-width:780px;margin:0 auto;padding:14px}
    .top{position:sticky;top:0;background:rgba(11,15,25,.92);backdrop-filter:blur(8px);border-bottom:1px solid rgba(34,48,85,.6);padding:12px 14px;z-index:10}
    .title{font-size:16px;font-weight:800}
    .subtitle{font-size:12px;color:var(--muted);margin-top:4px}
    .day{margin-top:14px}
    .dayHeader{margin:10px 2px 10px;padding:10px 12px;background:rgba(18,26,42,.7);border:1px solid rgba(34,48,85,.7);border-radius:var(--radius);box-shadow:var(--shadow)}
    .dayTitle{font-weight:900;font-size:14px}
    .daySub{color:var(--muted);font-size:12px;margin-top:4px}
    .deptoCard{margin-top:10px;border-radius:var(--radius);overflow:hidden;border:1px solid rgba(34,48,85,.7);background:var(--card);box-shadow:var(--shadow)}
    .deptoHeader{padding:12px;background:var(--card2);border-bottom:1px solid rgba(34,48,85,.7)}
    .deptoName{font-weight:900}
    .deptoItems{padding:10px}
    .item{border:1px solid rgba(34,48,85,.7);border-radius:14px;padding:10px;margin-bottom:10px;background:rgba(255,255,255,.02)}
    .row{display:flex;gap:10px;align-items:flex-start;margin:4px 0}
    .tag{min-width:64px;font-size:11px;font-weight:900;text-align:center;padding:6px 8px;border-radius:999px;border:1px solid rgba(255,255,255,.12)}
    .tagBlue{background:rgba(59,130,246,.18);color:#cfe2ff;border-color:rgba(59,130,246,.35)}
    .tagGreen{background:rgba(34,197,94,.18);color:#d3ffe2;border-color:rgba(34,197,94,.35)}
    .tagRed{background:rgba(239,68,68,.18);color:#ffd2d2;border-color:rgba(239,68,68,.35)}
    .text{flex:1}
    .main{font-size:13px}
    .sub{font-size:12px;color:var(--muted);margin-top:2px}
    .muted{color:var(--muted)}
    .strong{font-weight:900}
    .red{color:#ffb4b4}
    .link{color:#cfe2ff;text-decoration:none;border-bottom:1px dotted rgba(207,226,255,.5)}
    .footer{color:var(--muted);font-size:11px;text-align:center;padding:14px 0 18px}
  </style>
</head>
<body>
  <div class="top">
    <div class="title">Aseos v2 · API Stays · SandiegoApart</div>
    <div class="subtitle">Ventana: ${escapeHtml(ddmmyyyy(fechaDesde))} → ${escapeHtml(ddmmyyyy(fechaHasta))} · Actualizado: ${escapeHtml(actualizado)} (America/Santiago)</div>
  </div>
  <div class="wrap">
    ${body || `<div class="dayHeader"><div class="dayTitle">Sin check-outs</div><div class="daySub">No hay reservas con checkout entre ${escapeHtml(ddmmyyyy(fechaDesde))} y ${escapeHtml(ddmmyyyy(fechaHasta))}.</div></div>`}
    <div class="footer">Datos en tiempo real desde Stays.net API · Workflow n8n v2</div>
  </div>
</body>
</html>`;

return [{ json: { html } }];
